<!DOCTYPE html>
<html lang="en">
<head>
  <meta charset="UTF-8">
  <meta name="viewport" content="width=device-width, initial-scale=1.0">
  <title>Personal Expense Tracker</title>
  <style>
    :root {
      color-scheme: light;
      font-family: Arial, sans-serif;
      background: #f4f6f8;
      color: #1f2933;
    }

    * {
      box-sizing: border-box;
    }

    body {
      margin: 0;
      padding: 24px;
    }

    main {
      width: min(900px, 100%);
      margin: 0 auto;
    }

    h1, h2 {
      margin-top: 0;
    }

    .panel {
      background: #fff;
      border: 1px solid #d9e0e6;
      border-radius: 8px;
      padding: 20px;
      margin-bottom: 20px;
      box-shadow: 0 2px 6px rgba(0, 0, 0, 0.04);
    }

    .form-grid,
    .filter-grid {
      display: grid;
      grid-template-columns: repeat(auto-fit, minmax(160px, 1fr));
      gap: 14px;
      align-items: end;
    }

    label {
      display: flex;
      flex-direction: column;
      gap: 6px;
      font-weight: 600;
      font-size: 0.9rem;
    }

    input,
    select,
    button {
      font: inherit;
      min-height: 40px;
      border: 1px solid #b8c2cc;
      border-radius: 5px;
      padding: 8px 10px;
    }

    button {
      cursor: pointer;
      background: #2563eb;
      color: #fff;
      border-color: #2563eb;
      font-weight: 600;
    }

    button:hover {
      background: #1d4ed8;
    }

    .error {
      min-height: 1.3em;
      margin: 12px 0 0;
      color: #b42318;
      font-weight: 600;
    }

    .summary-total {
      font-size: 1.25rem;
      font-weight: 700;
      margin-bottom: 16px;
    }

    .category-summary {
      display: grid;
      grid-template-columns: repeat(auto-fit, minmax(130px, 1fr));
      gap: 10px;
      margin-bottom: 20px;
    }

    .cat-total {
      background: #eef2ff;
      border-radius: 5px;
      padding: 10px;
      font-size: 0.95rem;
    }

    .expense-list {
      display: grid;
      gap: 10px;
    }

    .expense {
      display: grid;
      grid-template-columns: 1fr auto;
      gap: 12px;
      align-items: center;
      border: 1px solid #d9e0e6;
      border-radius: 6px;
      padding: 12px;
      background: #fafbfc;
    }

    .expense-details {
      display: flex;
      flex-wrap: wrap;
      gap: 8px 18px;
      align-items: baseline;
    }

    .expense-amount {
      font-weight: 700;
    }

    .expense-category {
      text-transform: capitalize;
    }

    .expense-date {
      color: #586674;
      font-size: 0.9rem;
    }

    .exp-del {
      background: #dc2626;
      border-color: #dc2626;
      min-height: 34px;
    }

    .exp-del:hover {
      background: #b91c1c;
    }

    .empty {
      color: #586674;
      padding: 12px 0;
    }

    @media (max-width: 520px) {
      body {
        padding: 12px;
      }

      .panel {
        padding: 15px;
      }

      .expense {
        grid-template-columns: 1fr;
      }

      .exp-del {
        width: 100%;
      }
    }
  </style>
</head>
<body>
  <main>
    <section class="panel">
      <h1>Personal Expense Tracker</h1>
      <form id="expense-form">
        <div class="form-grid">
          <label>
            Amount
            <input id="amount" name="amount" type="number" min="0" step="0.01" inputmode="decimal">
          </label>

          <label>
            Category
            <select id="category" name="category">
              <option value="groceries">Groceries</option>
              <option value="transport">Transport</option>
              <option value="bills">Bills</option>
              <option value="fun">Fun</option>
            </select>
          </label>

          <label>
            Date
            <input id="date" name="date" type="date">
          </label>

          <label>
            Note
            <input id="note" name="note" type="text" maxlength="200">
          </label>

          <button id="add-expense" type="submit">Add Expense</button>
        </div>
        <p id="form-error" class="error" role="alert"></p>
      </form>
    </section>

    <section class="panel">
      <h2>Filters</h2>
      <div class="filter-grid">
        <label>
          Category
          <select id="filter-category">
            <option value="all">All categories</option>
            <option value="groceries">Groceries</option>
            <option value="transport">Transport</option>
            <option value="bills">Bills</option>
            <option value="fun">Fun</option>
          </select>
        </label>

        <label>
          From
          <input id="filter-from" type="date">
        </label>

        <label>
          To
          <input id="filter-to" type="date">
        </label>
      </div>
    </section>

    <section class="panel">
      <h2>Summary</h2>
      <div class="summary-total">Total: <span id="total">0.00</span></div>

      <div class="category-summary">
        <div class="cat-total" data-cat="groceries">Groceries: 0.00</div>
        <div class="cat-total" data-cat="transport">Transport: 0.00</div>
        <div class="cat-total" data-cat="bills">Bills: 0.00</div>
        <div class="cat-total" data-cat="fun">Fun: 0.00</div>
      </div>

      <div id="expense-list" class="expense-list">
        <div id="empty-message" class="empty">No expenses yet.</div>
      </div>
    </section>
  </main>

  <script>
    (function () {
      "use strict";

      const STORAGE_KEY = "expenses";
      const categories = ["groceries", "transport", "bills", "fun"];
      const form = document.getElementById("expense-form");
      const amountInput = document.getElementById("amount");
      const categoryInput = document.getElementById("category");
      const dateInput = document.getElementById("date");
      const noteInput = document.getElementById("note");
      const formError = document.getElementById("form-error");
      const filterCategory = document.getElementById("filter-category");
      const filterFrom = document.getElementById("filter-from");
      const filterTo = document.getElementById("filter-to");
      const list = document.getElementById("expense-list");
      const totalElement = document.getElementById("total");
      const emptyMessage = document.getElementById("empty-message");

      let expenses = loadExpenses();

      function loadExpenses() {
        try {
          const stored = localStorage.getItem(STORAGE_KEY);
          const parsed = stored ? JSON.parse(stored) : [];
          return Array.isArray(parsed) ? parsed : [];
        } catch (error) {
          return [];
        }
      }

      function saveExpenses() {
        try {
          localStorage.setItem(STORAGE_KEY, JSON.stringify(expenses));
        } catch (error) {
          // The tracker remains usable if storage is unavailable.
        }
      }

      function getVisibleExpenses() {
        const selectedCategory = filterCategory.value;
        const from = filterFrom.value;
        const to = filterTo.value;

        return expenses.filter(function (expense) {
          const categoryMatches =
            selectedCategory === "all" || expense.category === selectedCategory;
          const fromMatches = !from || expense.date >= from;
          const toMatches = !to || expense.date <= to;
          return categoryMatches && fromMatches && toMatches;
        });
      }

      function render() {
        const visibleExpenses = getVisibleExpenses();
        const visibleIds = new Set(visibleExpenses.map(function (expense) {
          return String(expense.id);
        }));

        list.querySelectorAll(".expense").forEach(function (row) {
          row.remove();
        });

        const orderedExpenses = expenses.slice().sort(function (a, b) {
          if (a.date !== b.date) {
            return b.date.localeCompare(a.date);
          }
          return Number(b.createdAt || 0) - Number(a.createdAt || 0);
        });

        orderedExpenses.forEach(function (expense) {
          const row = document.createElement("div");
          row.className = "expense";
          row.dataset.id = String(expense.id);
          row.style.display = visibleIds.has(String(expense.id)) ? "" : "none";

          const details = document.createElement("div");
          details.className = "expense-details";

          const amount = document.createElement("span");
          amount.className = "expense-amount";
          amount.textContent = Number(expense.amount).toFixed(2);

          const category = document.createElement("span");
          category.className = "expense-category";
          category.textContent = expense.category;

          const date = document.createElement("span");
          date.className = "expense-date";
          date.textContent = expense.date;

          details.append(amount, category, date);

          if (expense.note) {
            const note = document.createElement("span");
            note.className = "expense-note";
            note.textContent = expense.note;
            details.append(note);
          }

          const deleteButton = document.createElement("button");
          deleteButton.type = "button";
          deleteButton.className = "exp-del";
          deleteButton.textContent = "Delete";
          deleteButton.addEventListener("click", function () {
            expenses = expenses.filter(function (item) {
              return String(item.id) !== String(expense.id);
            });
            saveExpenses();
            render();
          });

          row.append(details, deleteButton);
          list.appendChild(row);
        });

        emptyMessage.style.display = expenses.length ? "none" : "";
        updateSummary(visibleExpenses);
      }

      function updateSummary(visibleExpenses) {
        const total = visibleExpenses.reduce(function (sum, expense) {
          return sum + Number(expense.amount);
        }, 0);

        totalElement.textContent = total.toFixed(2);

        categories.forEach(function (categoryName) {
          const categoryTotal = visibleExpenses
            .filter(function (expense) {
              return expense.category === categoryName;
            })
            .reduce(function (sum, expense) {
              return sum + Number(expense.amount);
            }, 0);

          const element = document.querySelector(
            '.cat-total[data-cat="' + categoryName + '"]'
          );
          if (element) {
            element.textContent =
              categoryName.charAt(0).toUpperCase() +
              categoryName.slice(1) +
              ": " +
              categoryTotal.toFixed(2);
          }
        });
      }

      form.addEventListener("submit", function (event) {
        event.preventDefault();

        const amount = Number(amountInput.value);
        const date = dateInput.value;

        if (!amountInput.value.trim() || !Number.isFinite(amount) || amount <= 0) {
          formError.textContent = "Enter a valid amount greater than zero.";
          return;
        }

        if (!date) {
          formError.textContent = "Please select a date.";
          return;
        }

        formError.textContent = "";

        expenses.push({
          id: Date.now().toString() + Math.random().toString(16).slice(2),
          amount: amount,
          category: categoryInput.value,
          date: date,
          note: noteInput.value.trim(),
          createdAt: Date.now()
        });

        saveExpenses();
        amountInput.value = "";
        render();
      });

      [filterCategory, filterFrom, filterTo].forEach(function (control) {
        control.addEventListener("change", render);
        control.addEventListener("input", render);
      });

      render();
    })();
  </script>
</body>
</html>
